{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 1,
      "content": {
        "json": "# Is AI Native Monitoring\n\nAzure Workbook for scan and report telemetry. These queries use the `customEvents` table populated by the backend Application Insights telemetry integration."
      },
      "name": "text - intro"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "customEvents\n| where name == \"scan_completed\"\n| summarize total_scans = count()",
        "size": 0,
        "title": "Total scans",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "table",
        "exportToExcelOptions": "visible"
      },
      "name": "query - total scans"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "customEvents\n| where name == \"report_created\"\n| summarize total_reports = count()",
        "size": 0,
        "title": "Total reports",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "table",
        "exportToExcelOptions": "visible"
      },
      "name": "query - total reports"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "customEvents\n| where name == \"scan_completed\"\n| project timestamp, repo_name = tostring(customDimensions.repo_name), verdict = tostring(customDimensions.verdict), score = todouble(customMeasurements.score), duration_ms = todouble(customMeasurements.duration_ms)\n| order by timestamp desc",
        "size": 1,
        "title": "Recent scans",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "table",
        "exportToExcelOptions": "visible"
      },
      "name": "query - recent scans"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "let scans = customEvents\n| where name == \"scan_completed\"\n| project scan_key = tostring(customDimensions.scan_key), scan_time = timestamp, repo_name = tostring(customDimensions.repo_name), score = todouble(customMeasurements.score), verdict = tostring(customDimensions.verdict);\nlet reports = customEvents\n| where name == \"report_created\"\n| project scan_key = tostring(customDimensions.scan_key), report_time = timestamp, report_id = tostring(customDimensions.report_id);\nscans\n| join kind=leftouter reports on scan_key\n| order by scan_time desc",
        "size": 1,
        "title": "Recent reports joined to scans",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "table",
        "exportToExcelOptions": "visible"
      },
      "name": "query - reports joined"
    }
  ],
  "isLocked": false,
  "fallbackResourceIds": []
}
